int lastStoneWeight(vector<int>& stones) {
    priority_queue<int> pq(stones.begin(), stones.end());
    while (pq.size() > 1) {
        int s1 = pq.top(); pq.pop();
        int s2 = pq.top(); pq.pop();
        if (s1 != s2) {
            pq.push(s1 - s2);
        }
    }
    return pq.empty() ? 0 : pq.top();
}

vector<string> findRelativeRanks(vector<int>& score) {
    int n = score.size();
    priority_queue<pair<int, int>> pq; // {score, index}
    for (int i = 0; i < n; ++i) {
        pq.push({score[i], i});
    }
    vector<string> res(n);
    int rank = 1;
    while (!pq.empty()) {
        auto [val, idx] = pq.top(); pq.pop();
        if (rank == 1) res[idx] = "Gold Medal";
        else if (rank == 2) res[idx] = "Silver Medal";
        else if (rank == 3) res[idx] = "Bronze Medal";
        else res[idx] = to_string(rank);
        rank++;
    }
    return res;
}

