import collections, heapq
def topKFrequent(nums: list[int], k: int) -> list[int]:
    counts = collections.Counter(nums)
    heap = []
    for num, freq in counts.items():
        heapq.heappush(heap, (freq, num))
        if len(heap) > k:
            heapq.heappop(heap)
    return [item[1] for item in heap]

