import heapq
def getSkyline(buildings: list[list[int]]) -> list[list[int]]:
    events = []
    for L, R, H in buildings:
        events.append((L, -H, R)) # start event
        events.append((R, 0, 0))   # end event
    events.sort()
    res = [[0, 0]]
    active = [(0, float('inf'))] # stores (-height, right_edge)
    for x, h, r in events:
        if h < 0:
            heapq.heappush(active, (h, r))
        while active[0][1] <= x:
            heapq.heappop(active)
        curr_max = -active[0][0]
        if res[-1][1] != curr_max:
            res.append([x, curr_max])
    return res[1:]

cppCode:
vector<vector<int>> getSkyline(vector<vector<int>>& buildings) {
    vector<pair<int, int>> events;
    for (auto& b : buildings) {
        events.push_back({b[0], -b[2]});
        events.push_back({b[1], b[2]});
    }
    sort(events.begin(), events.end());
    multiset<int> active = {0};
    vector<vector<int>> res;
    int prev_max = 0;
    for (auto& [x, h] : events) {
        if (h < 0) {
            active.insert(-h);
        } else {
            active.erase(active.find(h));
        }
        int curr_max = *active.rbegin();
        if (curr_max != prev_max) {
            res.push_back({x, curr_max});
            prev_max = curr_max;
        }
    }
    return res;
}
